/// Start a new workflow execution
/// 
/// # Responses
/// - 201 Created: Workflow started successfully
/// - 404 Not Found: Workflow definition not found
/// - 409 Conflict: At capacity (max concurrent workflows reached)
#[utoipa::path(
    post,
    path = "/api/v1/workflows",
    request_body = StartWorkflowRequest,
    responses(
        (status = 201, description = "Workflow started"),
        (status = 404, description = "Workflow not found"),
        (status = 409, description = "At capacity")
    )
)]
pub async fn start_workflow(...) -> ... { }
```

